mapper.select:
SELECT * FROM orders
WHERE status = 'PENDING_PAYMENT'
  AND created_at <= #{cutoff}

mapper.update:
UPDATE orders
SET status = 'RETURN_APPROVED',
    return_approved_at = NOW(),
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}

UPDATE orders
SET status = #{status},
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}
